import { Component, Input } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { Booking } from '@placeos/bookings';
import { SettingsService } from '@placeos/common';
import { GroupEventDetailsModalComponent } from './group-event-details-modal.component';

@Component({
    selector: 'group-event-card',
    template: `
        <button
            matRipple
            (click)="viewDetails()"
            class="border border-base-300 flex flex-col bg-base-100 rounded-xl shadow overflow-hidden w-64 h-[20rem]"
        >
            <div
                class="flex items-center justify-between h-28 w-full bg-base-200 overflow-auto"
            >
                <img
                    *ngIf="event.images?.length"
                    auth
                    [source]="event.images[0]"
                    class="object-cover"
                />
            </div>
            <div class="p-4 flex-1 h-1/2">
                <div class="opacity-60 text-sm">
                    {{ event.date | date: 'EEE d MMM' }},
                    {{ event.date | date: time_format }}
                </div>
                <h2 class="text-xl mb-2">{{ event.title }}</h2>
                <div
                    class="opacity-60 text-xs flex-1 overflow-hidden h-[4.5rem] mb-2"
                >
                    {{ event.description }}
                </div>
                <div class="flex items-center space-x-2 text-xs mb-1">
                    <app-icon class="text-info">place</app-icon>
                    <div class="" *ngIf="event.location">
                        {{ event.location }}
                    </div>
                    <div class="opacity-30" *ngIf="!event.location">
                        Remote event
                    </div>
                </div>
                <div class="flex items-center space-x-2 text-xs">
                    <app-icon class="text-info">people</app-icon>
                    <div class="">
                        {{ event.attendees?.length || '0' }} attending
                    </div>
                </div>
            </div>
        </button>
    `,
    styles: [``],
})
export class GroupEventCardComponent {
    @Input() public event: any;

    public get time_format(): string {
        return this._settings.time_format;
    }

    constructor(
        private _settings: SettingsService,
        private _dialog: MatDialog
    ) {}

    public ngOnInit(): void {}

    public viewDetails(): void {
        this._dialog.open(GroupEventDetailsModalComponent, {
            data: this.event,
        });
    }
}
